class Solution:
    def lastRemaining(self, n):
        # Independent recurrence: left-to-right then mirror the right-to-left pass.
        def lr(m):
            if m == 1:
                return 1
            return 2 * rl(m // 2)
        def rl(m):
            if m == 1:
                return 1
            if m % 2 == 0:
                return 2 * lr(m // 2) - 1
            return 2 * lr(m // 2)
        return lr(n)

